411	    /// Expands ${VAR} and ${VAR?} environment variable substitutions in a string.
412	    /// Used for quoted values after JSON parsing has already handled escape sequences.
413	    ///
414	    /// Behavior (same as unquoted):
415	    /// - ${VAR} - if VAR is undefined, leave as "${VAR}" (no expansion)
416	    /// - ${VAR?} - if VAR is undefined, expand to empty string
417	    /// - Backslash escaping is already handled by JSON parsing
418	    fn expandEnvVars(this: *Parser, allocator: Allocator, val: []const u8) OOM![]const u8 {
419	        // Quick check if there are any env vars to expand
420	        if (std.mem.indexOf(u8, val, "${") == null) {
421	            return val;
422	        }
423	
424	        var result = try std.array_list.Managed(u8).initCapacity(allocator, val.len);
425	        var i: usize = 0;
426	        while (i < val.len) {
427	            if (val[i] == '$' and i + 2 < val.len and val[i + 1] == '{') {
428	                // Find the closing brace
429	                var j = i + 2;
430	                var depth: usize = 1;
431	                while (j < val.len and depth > 0) {
432	                    if (val[j] == '{') {
433	                        depth += 1;
434	                    } else if (val[j] == '}') {
435	                        depth -= 1;
436	                    }
437	                    if (depth > 0) j += 1;
438	                }
439	                if (depth == 0) {
440	                    const env_var_raw = val[i + 2 .. j];
441	                    const optional = env_var_raw.len > 0 and env_var_raw[env_var_raw.len - 1] == '?';
442	                    const env_var = if (optional) env_var_raw[0 .. env_var_raw.len - 1] else env_var_raw;
443	
444	                    if (this.env.get(env_var)) |expanded| {
445	                        try result.appendSlice(expanded);
446	                    } else if (!optional) {
447	                        // Not found and not optional: leave as-is
448	                        try result.appendSlice(val[i .. j + 1]);
449	                    }
450	                    // If optional and not found: expand to empty string (append nothing)
451	                    i = j + 1;
452	                    continue;
453	                }
454	            }
455	            try result.append(val[i]);
456	            i += 1;
457	        }
458	        return result.items;
