513	    fn singleStrRope(ropealloc: Allocator, str: []const u8) OOM!*Rope {
514	        const rope = try ropealloc.create(Rope);
515	        rope.* = .{
516	            .head = Expr.init(E.String, E.String.init(str), Loc.Empty),
517	        };
518	        return rope;
519	    }
520	
521	    fn nextDot(key: []const u8) ?usize {
522	        return std.mem.indexOfScalar(u8, key, '.');
523	    }
524	
525	    fn commitRopePart(this: *Parser, arena_allocator: Allocator, ropealloc: Allocator, unesc: *std.array_list.Managed(u8), existing_rope: *?*Rope) OOM!void {
526	        _ = this; // autofix
527	        const slice = try arena_allocator.dupe(u8, unesc.items[0..]);
528	        const expr = Expr.init(E.String, E.String{ .data = slice }, Loc.Empty);
529	        if (existing_rope.*) |_r| {
530	            const r: *Rope = _r;
531	            _ = try r.append(expr, ropealloc);
532	        } else {
533	            existing_rope.* = try ropealloc.create(Rope);
534	            existing_rope.*.?.* = Rope{
535	                .head = expr,
536	            };
537	        }
538	        unesc.clearRetainingCapacity();
539	    }
540	
541	    fn strToRope(ropealloc: Allocator, key: []const u8) OOM!*Rope {
542	        var dot_idx = nextDot(key) orelse {
543	            const rope = try ropealloc.create(Rope);
544	            rope.* = .{
545	                .head = Expr.init(E.String, E.String.init(key), Loc.Empty),
546	            };
547	            return rope;
548	        };
549	        var rope = try ropealloc.create(Rope);
550	        const head = rope;
551	        rope.* = .{
552	            .head = Expr.init(E.String, E.String.init(key[0..dot_idx]), Loc.Empty),
553	            .next = null,
554	        };
555	
556	        while (dot_idx + 1 < key.len) {
557	            const next_dot_idx = dot_idx + 1 + (nextDot(key[dot_idx + 1 ..]) orelse {
558	                const rest = key[dot_idx + 1 ..];
559	                rope = try rope.append(Expr.init(E.String, E.String.init(rest), Loc.Empty), ropealloc);
560	                break;
561	            });
562	            const part = key[dot_idx + 1 .. next_dot_idx];
563	            rope = try rope.append(Expr.init(E.String, E.String.init(part), Loc.Empty), ropealloc);
564	            dot_idx = next_dot_idx;
565	        }
566	
567	        return head;
568	    }
